SELECT

FROM t_recharge_order
WHERE is_deleted = 0
  AND payment_status IN

      #{status}

  AND create_time <= #{beforeTime}
ORDER BY create_time ASC
LIMIT #{limit}

SELECT

FROM t_recharge_order
WHERE user_id = #{userId}
  AND is_deleted = 0

      AND payment_method = #{paymentMethod}

ORDER BY create_time DESC
